#include <stdio.h>
#include <stdbool.h>

bool isLeap(int y){
    return (y%400==0) || (y%4==0 && y%100!=0);
}

bool valid(int d,int m,int y){
    if(m<1||m>12||d<1) return false;
    int mdays[]={0,31,28,31,30,31,30,31,31,30,31,30,31};
    if(m==2 && isLeap(y)) mdays[2]=29;
    return d<=mdays[m];
}

int main(){
    int T; if(scanf("%d",&T)!=1) return 0;
    while(T--){
        int a,b,y; scanf(" %d/%d/%d",&a,&b,&y);
        bool first = valid(a,b,y); // DD/MM
        bool second = valid(b,a,y); // MM/DD
        if(first && second) printf("BOTH\n");
        else if(first) printf("DD/MM/YYYY\n");
        else printf("MM/DD/YYYY\n");
    }
    return 0;
}

