code.Python3:
#!/usr/bin/env python3
import sys

def is_leap(y: int) -> bool:
    return (y % 400 == 0) or (y % 4 == 0 and y % 100 != 0)

def valid(d: int, m: int, y: int) -> bool:
    if m < 1 or m > 12 or d < 1:
        return False
    mdays = [0,31,28,31,30,31,30,31,31,30,31,30,31]
    days = mdays[m]
    if m == 2 and is_leap(y):
        days = 29
    return d <= days

def main():
    data = sys.stdin.read().strip().splitlines()
    if not data:
        return
    T = int(data[0])
    out = []
    for i in range(1, T+1):
        s = data[i].strip()
        a = int(s[0:2])
        b = int(s[3:5])
        y = int(s[6:10])
        first = valid(a, b, y)   # DD/MM
        second = valid(b, a, y)  # MM/DD
        if first and second:
            out.append("BOTH")
        elif first:
            out.append("DD/MM/YYYY")
        else:
            out.append("MM/DD/YYYY")
    sys.stdout.write("\n".join(out))

if __name__ == "__main__":
    main()

